define('generis.tree',['jquery', 'i18n', 'class'], function ($, __, Class) {
  var GenerisTreeClass = Class.extend({
    init: function init(selector, dataUrl, options, treeOptions) {
      var self = this;
      this.STATE_BROWSING = 0;
      this.STATE_FILTERING = 1;
      this.selector = selector;
      this.options = options;
      this.dataUrl = dataUrl;
      this.metaClasses = [];
      this.lastOpened = null;
      this.state = this.STATE_BROWSING;
      this.paginate = typeof options.paginate !== 'undefined' ? options.paginate : 0;
      this.serverParameters = typeof options.serverParameters !== "undefined" ? options.serverParameters : new Array();
      this.defaultServerParameters = {
        hideInstances: this.options.hideInstances | false,
        filter: $("#filter-content-" + options.actionId).val(),
        offset: 0,
        limit: this.options.paginate
      };
      this.treeOptions = {
        data: {
          type: "json",
          async: true,
          opts: {
            method: "POST",
            url: this.dataUrl
          }
        },
        types: {
          "default": {
            renameable: false,
            deletable: true,
            creatable: true
          }
        },
        callback: {
          beforeopen: function beforeopen(NODE, TREE_OBJ) {
            self.lastOpened = NODE;
          }
        }
      };
      $.extend(true, this.treeOptions, treeOptions);
      var classes = $(selector).attr('class');
      if (typeof classes != 'string' || classes.match('tree') == null) {
        $(selector).tree(this.treeOptions);
      }
    },
    createMeta: function createMeta(meta) {
      this.metaClasses[meta.id] = {
        displayed: meta.displayed ? meta.displayed : 0,
        count: meta.count ? meta.count : 0,
        position: meta.position ? meta.position : 0
      };
    },
    extractMeta: function extractMeta(DATA) {
      var nodes = new Array();
      var nodeId = null;
      if (!(DATA instanceof Array)) {
        nodeId = DATA.attributes.id;
        if (typeof DATA.children != 'undefined') {
          nodes = DATA.children;
        }
        this.createMeta({
          id: DATA.attributes.id,
          count: DATA.count
        });
      } else {
        if (this.lastOpened && this.state != this.STATE_FILTERING) {
          nodeId = this.lastOpened.id;
        } else {
          nodeId = "DEFAULT_ROOT";
          this.createMeta({
            id: nodeId,
            count: 0
          });
        }
        nodes = DATA;
      }
      if (nodes.length !== 0) {
        var countClass = 0;
        for (var i = 0; i < nodes.length; i++) {
          if (nodes[i].type == 'class') {
            this.extractMeta(nodes[i]);
            countClass++;
          }
        }
        var countInstances = nodes.length - countClass;
        this.setMeta(nodeId, 'position', countInstances);
        this.setMeta(nodeId, 'displayed', countInstances);
        if (!(DATA instanceof Array) && DATA.state && DATA.state != 'closed') {
          if (this.getMeta(nodeId, 'displayed') < this.getMeta(nodeId, 'count')) {
            nodes.push(this.getPaginateActionNodes());
          }
        } else if (DATA instanceof Array && this.getMeta(nodeId, 'displayed') < this.getMeta(nodeId, 'count')) {
          nodes.push(this.getPaginateActionNodes());
        }
      }
    },
    setServerParameter: function setServerParameter(key, value, reload) {
      this.serverParameters[key] = value;
      if (typeof reload != 'undefined' && reload) {
        this.isRefreshing = true;
        this.getTree().refresh();
      }
    },
    getTree: function getTree() {
      return $.tree.reference(this.selector);
    },
    getMeta: function getMeta(classId, metaName, value) {
      return this.metaClasses[classId][metaName];
    },
    setMeta: function setMeta(classId, metaName, value) {
      this.metaClasses[classId][metaName] = value;
    },
    getPaginateActionNodes: function getPaginateActionNodes() {
      returnValue = [{
        'data': __('all'),
        'attributes': {
          'class': 'paginate paginate-all'
        }
      }, {
        'data': this.paginate + __(' next'),
        'attributes': {
          'class': 'paginate paginate-more'
        }
      }];
      return returnValue;
    },
    showPaginate: function showPaginate(NODE, TREE_OBJ) {
      var DATA = this.getPaginateActionNodes();
      for (var i = 0; i < DATA.length; i++) {
        TREE_OBJ.create(DATA[i], TREE_OBJ.get_node(NODE[0]));
      }
    },
    hidePaginate: function hidePaginate(nodeId) {
      $('#' + nodeId + ' > ul > li.paginate', $(this.selector)).each(function () {
        $(this).remove();
      });
    },
    refreshPaginate: function refreshPaginate(NODE, TREE_OBJ) {
      var nodeId = $(NODE)[0].id;
      this.hidePaginate(nodeId);
      if (this.getMeta(nodeId, "displayed") < this.getMeta(nodeId, "count")) {
        this.showPaginate(NODE, TREE_OBJ);
      }
    },
    getClassUri: function getClassUri(NODE) {
      var parents = $(NODE).parents('li');
      var classUri = null;
      if (parents.length == 0) classUri = $(NODE).prop('id');else classUri = $(parents[0]).prop('id');
      return classUri;
    },
    callGetSectionActions: function callGetSectionActions(NODE, TREE_OBJ) {
      var uri = undefined;
      var classUri = undefined;
      if (NODE != undefined) {
        if ($(NODE).hasClass('node-class')) {
          classUri = $(NODE).prop('id');
        } else {
          uri = $(NODE).prop('id');
          classUri = this.getClassUri(NODE);
        }
      }
    }
  });
  return GenerisTreeClass;
});
