define('controller/entry',['jquery', 'lodash', 'i18n', 'ui/feedback'], function ($, _, __, feedback) {
  'use strict';
  return {
    start: function start() {
      var $container = $('#entry-point-box');
      var errorMessage = $container.data('errormessage');
      if (errorMessage) {
        feedback().error(errorMessage);
      }
    }
  };
});
